 30→class Preferences internal constructor(
 31→    private val storagePersister: StoragePersister,
 32→    private val localStoreProvider: LocalStoreProvider,
 33→    private val accountPreferenceSerializer: AccountPreferenceSerializer,
 34→    private val backgroundDispatcher: CoroutineDispatcher = Dispatchers.IO,
 35→) : AccountManager {
 36→    private val accountLock = Any()
 37→    private val storageLock = Any()
 38→
 39→    @GuardedBy("accountLock")
 40→    private var accountsMap: MutableMap<String, Account>? = null
 41→
 42→    @GuardedBy("accountLock")
 43→    private var accountsInOrder = mutableListOf<Account>()
 44→
 45→    @GuardedBy("accountLock")
 46→    private var newAccount: Account? = null
 47→    private val accountsChangeListeners = CopyOnWriteArraySet<AccountsChangeListener>()
 48→    private val accountRemovedListeners = CopyOnWriteArraySet<AccountRemovedListener>()
 49→
 50→    @GuardedBy("storageLock")
 51→    private var currentStorage: Storage? = null
 52→
 53→    val storage: Storage
 54→        get() = synchronized(storageLock) {
 55→            currentStorage ?: storagePersister.loadValues().also { newStorage ->
 56→                currentStorage = newStorage
 57→            }
 58→        }
 59→
 60→    fun createStorageEditor(): StorageEditor {
 61→        return storagePersister.createStorageEditor { updater ->
 62→            synchronized(storageLock) {
 63→                currentStorage = updater(storage)
 64→            }
 65→        }
 66→    }
 67→
 68→    @RestrictTo(RestrictTo.Scope.TESTS)
 69→    fun clearAccounts() {
 70→        synchronized(accountLock) {
 71→            accountsMap = HashMap()
 72→            accountsInOrder = LinkedList()
 73→        }
 74→    }
 75→
 76→    fun loadAccounts() {
 77→        synchronized(accountLock) {
 78→            val accounts = mutableMapOf<String, Account>()
 79→            val accountsInOrder = mutableListOf<Account>()
 80→
 81→            val accountUuids = storage.getString("accountUuids", null)
 82→            if (!accountUuids.isNullOrEmpty()) {
 83→                accountUuids.split(",").forEach { uuid ->
 84→                    val existingAccount = accountsMap?.get(uuid)
 85→                    val account = existingAccount ?: Account(uuid, K9::isSensitiveDebugLoggingEnabled)
 86→                    accountPreferenceSerializer.loadAccount(account, storage)
 87→
 88→                    accounts[uuid] = account
 89→                    accountsInOrder.add(account)
 90→                }
 91→            }
 92→
 93→            newAccount?.takeIf { it.accountNumber != -1 }?.let { newAccount ->
 94→                accounts[newAccount.uuid] = newAccount
 95→                if (newAccount !in accountsInOrder) {
 96→                    accountsInOrder.add(newAccount)
 97→                }
 98→                this.newAccount = null
 99→            }
100→
101→            this.accountsMap = accounts
102→            this.accountsInOrder = accountsInOrder
103→        }
104→    }
105→
106→    override fun getAccounts(): List<Account> {
107→        synchronized(accountLock) {
108→            if (accountsMap == null) {
109→                loadAccounts()
110→            }
111→
112→            return accountsInOrder.toList()
113→        }
114→    }
115→
116→    private val completeAccounts: List<Account>
117→        get() = getAccounts().filter { it.isFinishedSetup }
118→
119→    override fun getAccount(accountUuid: String): Account? {
120→        synchronized(accountLock) {
121→            if (accountsMap == null) {
122→                loadAccounts()
123→            }
124→
125→            return accountsMap!![accountUuid]
126→        }
127→    }
128→
129→    override fun getAccountFlow(accountUuid: String): Flow<Account> {
130→        return callbackFlow {
131→            val initialAccount = getAccount(accountUuid)
132→            if (initialAccount == null) {
133→                close()
134→                return@callbackFlow
135→            }
136→
137→            send(initialAccount)
138→
139→            val listener = AccountsChangeListener {
140→                val account = getAccount(accountUuid)
141→                if (account != null) {
142→                    trySendBlocking(account)
143→                } else {
144→                    close()
145→                }
146→            }
147→            addOnAccountsChangeListener(listener)
148→
149→            awaitClose {
150→                removeOnAccountsChangeListener(listener)
151→            }
152→        }.buffer(capacity = Channel.CONFLATED)
153→            .flowOn(backgroundDispatcher)
154→    }
155→
156→    @OptIn(ExperimentalCoroutinesApi::class)
157→    override fun getAccountsFlow(): Flow<List<Account>> {
158→        return callbackFlow {
159→            send(completeAccounts)
160→
161→            val listener = AccountsChangeListener {
162→                trySendBlocking(completeAccounts)
163→            }
164→            addOnAccountsChangeListener(listener)
165→
166→            awaitClose {
167→                removeOnAccountsChangeListener(listener)
168→            }
169→        }.buffer(capacity = Channel.CONFLATED)
170→            .flowOn(backgroundDispatcher)
171→    }
172→
173→    fun newAccount(): Account {
174→        val accountUuid = UUID.randomUUID().toString()
175→        return newAccount(accountUuid)
176→    }
177→
178→    fun newAccount(accountUuid: String): Account {
179→        val account = Account(accountUuid, K9::isSensitiveDebugLoggingEnabled)
180→        accountPreferenceSerializer.loadDefaults(account)
181→
182→        synchronized(accountLock) {
183→            newAccount = account
184→            accountsMap!![account.uuid] = account
185→            accountsInOrder.add(account)
186→        }
187→
188→        return account
189→    }
190→
191→    fun deleteAccount(account: Account) {
192→        synchronized(accountLock) {
193→            accountsMap?.remove(account.uuid)
194→            accountsInOrder.remove(account)
195→
196→            val storageEditor = createStorageEditor()
197→            accountPreferenceSerializer.delete(storageEditor, storage, account)
198→            storageEditor.commit()
199→
200→            if (account === newAccount) {
201→                newAccount = null
202→            }
203→        }
204→
205→        notifyAccountRemovedListeners(account)
206→        notifyAccountsChangeListeners()
207→    }
208→
209→    val defaultAccount: Account?
210→        get() = getAccounts().firstOrNull()
211→
212→    override fun saveAccount(account: Account) {
213→        ensureAssignedAccountNumber(account)
214→        processChangedValues(account)
215→
216→        synchronized(accountLock) {
217→            val editor = createStorageEditor()
218→            accountPreferenceSerializer.save(editor, storage, account)
219→            editor.commit()
220→        }
221→
222→        notifyAccountsChangeListeners()
223→    }
224→
225→    private fun ensureAssignedAccountNumber(account: Account) {
226→        if (account.accountNumber != Account.UNASSIGNED_ACCOUNT_NUMBER) return
227→
228→        account.accountNumber = generateAccountNumber()
229→    }
230→
231→    private fun processChangedValues(account: Account) {
232→        if (account.isChangedVisibleLimits) {
233→            try {
234→                localStoreProvider.getInstance(account).resetVisibleLimits(account.displayCount)
235→            } catch (e: MessagingException) {
236→                Timber.e(e, "Failed to load LocalStore!")
237→            }
238→        }
239→        account.resetChangeMarkers()
240→    }
241→
242→    fun generateAccountNumber(): Int {
243→        val accountNumbers = getAccounts().map { it.accountNumber }
244→        return findNewAccountNumber(accountNumbers)
245→    }
246→
247→    private fun findNewAccountNumber(accountNumbers: List<Int>): Int {
248→        var newAccountNumber = -1
249→        for (accountNumber in accountNumbers.sorted()) {
250→            if (accountNumber > newAccountNumber + 1) {
251→                break
252→            }
253→            newAccountNumber = accountNumber
254→        }
255→        newAccountNumber++
256→
257→        return newAccountNumber
258→    }
259→
260→    override fun moveAccount(account: Account, newPosition: Int) {
261→        synchronized(accountLock) {
262→            val storageEditor = createStorageEditor()
263→            accountPreferenceSerializer.move(storageEditor, account, storage, newPosition)
264→            storageEditor.commit()
265→
266→            loadAccounts()
267→        }
268→
269→        notifyAccountsChangeListeners()
270→    }
271→
272→    private fun notifyAccountsChangeListeners() {
273→        for (listener in accountsChangeListeners) {
274→            listener.onAccountsChanged()
275→        }
276→    }
277→
278→    override fun addOnAccountsChangeListener(accountsChangeListener: AccountsChangeListener) {
279→        accountsChangeListeners.add(accountsChangeListener)
280→    }
281→
282→    override fun removeOnAccountsChangeListener(accountsChangeListener: AccountsChangeListener) {
283→        accountsChangeListeners.remove(accountsChangeListener)
284→    }
285→
286→    private fun notifyAccountRemovedListeners(account: Account) {
287→        for (listener in accountRemovedListeners) {
288→            listener.onAccountRemoved(account)
289→        }
290→    }
291→
292→    override fun addAccountRemovedListener(listener: AccountRemovedListener) {
293→        accountRemovedListeners.add(listener)
294→    }
295→
296→    fun removeAccountRemovedListener(listener: AccountRemovedListener) {
297→        accountRemovedListeners.remove(listener)
298→    }
299→
300→    companion object {
301→        @JvmStatic
302→        fun getPreferences(): Preferences {
303→            return DI.get()
304→        }
305→    }
306→}
